func Param(r ResourceParamsProvider, fallback maps.Params, key any) (any, error) {
	keyStr, err := cast.ToStringE(key)
	if err != nil {
		return nil, err
	}

	if fallback == nil {
		return maps.GetNestedParam(keyStr, ".", r.Params())
	}

	return maps.GetNestedParam(keyStr, ".", r.Params(), fallback)
}
